// GET /api/cameras - Fetch all cameras with their lifecycle logs
export async function GET() {
  try {
    const cameras = await prisma.camera.findMany({
      include: {
        contracts: true,
        maintenanceLogs: true,
        complianceAudits: true,
      },
      orderBy: {
        createdAt: 'desc',
      },
    });
    return NextResponse.json(cameras);
  } catch (error) {
    console.error('Failed to fetch cameras:', error);
    return NextResponse.json({ error: 'Failed to fetch cameras' }, { status: 500 });
  }
}

// POST /api/cameras - Provision a new camera asset dynamically into any stage
export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { name, modelNumber, macAddress, ipAddress, poeBudgetWatts, currentStage } = body;

    if (!name || !modelNumber || !macAddress || !ipAddress) {
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 });
    }

    const newCamera = await prisma.camera.create({
      data: {
        name,
        modelNumber,
        macAddress,
        ipAddress,
        poeBudgetWatts: parseFloat(poeBudgetWatts) || 0,
        currentStage: currentStage || 'BUY',
      },
    });

    return NextResponse.json(newCamera, { status: 201 });
  } catch (error: any) {
    console.error('Failed to create camera:', error);
    if (error.code === 'P2002') {
      return NextResponse.json({ error: 'A camera with this MAC address already exists' }, { status: 400 });
    }
    return NextResponse.json({ error: 'Failed to create camera' }, { status: 500 });
  }
}

// PATCH /api/cameras - Update an existing camera's stage from the card dropdown
export async function PATCH(request: Request) {
  try {
    const body = await request.json();
    const { id, currentStage } = body;

    if (!id || !currentStage) {
      return NextResponse.json({ error: 'Missing camera ID or target stage' }, { status: 400 });
    }

    const updatedCamera = await prisma.camera.update({
      where: { id },
      data: { currentStage },
    });

    return NextResponse.json(updatedCamera);
  } catch (error) {
    console.error('Failed to update camera stage:', error);
    return NextResponse.json({ error: 'Failed to update camera stage' }, { status: 500 });
  }
}